        for i in range(31):
            total = count[i] + carry
            if (target >> i) & 1:
                if total >= 1:
                    count[i] = total - 1
                    carry = 0
                else:
                    j = i + 1
                    while j < 31 and count[j] == 0:
                        j += 1
                    if j == 31:
                        return -1
                    operations += 1
                    count[j] -= 1
                    count[j-1] += 2
            else:
                carry = total

        return operations

class Solution:
    def minOperations(self, s1: str, s2: str, x: int) -> int:
        n = len(s1)
        diff = []
        for i in range(n):
            if s1[i] != s2[i]:
                diff.append(i)
        m = len(diff)
        if m % 2 != 0:
            return -1
        if m == 0:
            return 0
        diff.sort()
        # Initialize DP table
        dp = [[0] * m for _ in range(m)]
        # Fill for length 2
        for i in range(0, m, 2):
            j = i + 1
            if j < m:
                cost = min(x, diff[j] - diff[i])
                dp[i][j] = cost
        # Fill for longer lengths
        for length in range(4, m + 1, 2):
            for i in range(0, m - length + 1):
                j = i + length - 1
                # Option 1: pair i and j
                option1 = min(x, diff[j] - diff[i]) + dp[i+1][j-1]
                # Option 2: split into two parts
                option2 = float('inf')
                for k in range(i, j):
                    left_len = k - i + 1
                    right_len = j - k
                    if left_len % 2 == 0 and right_len % 2 == 0:
                        option2 = min(option2, dp[i][k] + dp[k+1][j])
                dp[i][j] = min(option1, option2)
        return dp[0][m-1]

class Solution:
    def numberOfPoints(self, nums: List[List[int]]) -> int:
        covered = [False] * 101
        for start, end in nums:
            for x in range(start, end + 1):
                covered[x] = True
        return sum(covered[1:])

