class Solution:
    def minimumRightShifts(self, nums: List[int]) -> int:
        n = len(nums)
        count = 0
        break_points = []
        for i in range(n - 1):
            if nums[i] > nums[i + 1]:
                count += 1
                break_points.append(i)
        if count == 0:
            return 0
        elif count == 1:
            if nums[-1] < nums[0]:
                i = break_points[0]
                return n - (i + 1)
            else:
                return -1
        else:
            return -1
